                );

            // === IDENTITY & SYMBOLS ===
            contentEl.createEl('h3', { text: 'Identity & symbols' });

            // Colors
            new Setting(contentEl)
                .setName('Colors')
                .setDesc('Faction colors (comma-separated)')
                .addText(text => text
