            const evt = this.allEvents.find(e => (e.id || e.name) === member.id);
            if (evt) {
                const tag = evtTagContainer.createSpan({ cls: 'group-tag' });
                const nameLink = tag.createEl('a', { text: evt.name, cls: 'group-member-link' });
