        itemSetting.addButton(btn => {
            btn.setButtonText(t('add')).setCta().onClick(() => {
                new PlotItemSuggestModal(this.app, this.plugin, (selectedItem) => { void (async () => {
                    const itemId = selectedItem.id || selectedItem.name;
                    if (selectedItem && !this.group.members.some(m => m.type === 'item' && m.id === itemId)) {
                        this.group.members.push({ type: 'item', id: itemId, name: selectedItem.name });
                        // Only update in settings if group already exists (not new)
                        if (!this.isNew && this.group.id) {
                            await this.plugin.addMemberToGroup(this.group.id, 'item', itemId);
                        }
                        this.renderMemberSelectors(container);
                    }
                })(); }).open();
            });
        });
    }

    // THIS is where the extra '}' was, which I removed.

    async syncMembers() {
        // Ensure plugin group members match modal state
        const group = this.plugin.getGroups().find(g => g.id === this.group.id);
        if (!group) return;
        // Remove members not in this.group.members
        for (const member of group.members) {
            if (!this.group.members.some(m => m.type === member.type && m.id === member.id)) {
                await this.plugin.removeMemberFromGroup(group.id, member.type, member.id);
            }
        }
        // Add members in this.group.members not in group.members
        for (const member of this.group.members) {
            if (!group.members.some(m => m.type === member.type && m.id === member.id)) {
                await this.plugin.addMemberToGroup(group.id, member.type, member.id);
            }
        }
    }

    private hasMultipleEntities(template: Template): boolean {
        let entityCount = 0;
        if (template.entities.groups?.length) entityCount += template.entities.groups.length;
        if (template.entities.characters?.length) entityCount += template.entities.characters.length;
        if (template.entities.locations?.length) entityCount += template.entities.locations.length;
        if (template.entities.events?.length) entityCount += template.entities.events.length;
        if (template.entities.items?.length) entityCount += template.entities.items.length;
        return entityCount > 1;
    }

    private async applyTemplateToGroup(template: Template): Promise<void> {
        if (!template.entities.groups || template.entities.groups.length === 0) {
            new Notice('This template does not contain any groups');
            return;
        }

        const templateGroup = template.entities.groups[0];
        await this.applyProcessedTemplateToGroup(templateGroup);
    }

    private async applyTemplateToGroupWithVariables(template: Template, variableValues: Record<string, any>): Promise<void> {
        if (!template.entities.groups || template.entities.groups.length === 0) {
            new Notice('This template does not contain any groups');
            return;
        }

        // Get the first group from the template
        let templateGroup = template.entities.groups[0];

        // Substitute variables with user-provided values
        const { VariableSubstitution } = await import('../templates/VariableSubstitution');
        const substitutionResult = VariableSubstitution.substituteEntity(
            templateGroup,
            variableValues,
            false // non-strict mode
        );
        templateGroup = substitutionResult.value;

        if (substitutionResult.warnings.length > 0) {
            console.warn('[GroupModal] Variable substitution warnings:', substitutionResult.warnings);
        }

        // Apply the substituted template
        await this.applyProcessedTemplateToGroup(templateGroup);
    }

    private async applyProcessedTemplateToGroup(templateGroup: any): Promise<void> {
        const { yamlContent, markdownContent, sectionContent, customYamlFields } = templateGroup;

        let fields: Record<string, any> = { ...templateGroup };
        delete fields.templateId;
        delete fields.yamlContent;
        delete fields.markdownContent;
        delete fields.sectionContent;
        delete fields.customYamlFields;
        delete fields.id;
        delete fields.filePath;
        delete fields.storyId;
        let allTemplateSections: Record<string, string> = {};

        // Handle new format: yamlContent (parse YAML string)
        if (yamlContent && typeof yamlContent === 'string') {
            try {
                const parsed = parseYaml(yamlContent);
                if (parsed && typeof parsed === 'object') {
                    fields = { ...fields, ...parsed };
                }
                console.debug('[GroupModal] Parsed YAML fields:', parsed);
            } catch (error) {
                console.warn('[GroupModal] Failed to parse yamlContent:', error);
            }
        } else if (customYamlFields) {
            // Old format: merge custom YAML fields
            fields = { ...fields, ...customYamlFields };
        }

        // Handle new format: markdownContent (parse sections)
        if (markdownContent && typeof markdownContent === 'string') {
            try {
                const parsedSections = parseSectionsFromMarkdown(`---\n---\n\n${markdownContent}`);
                allTemplateSections = parsedSections;

                // Map well-known sections to entity properties
                if ('Description' in parsedSections) {
                    fields.description = parsedSections['Description'];
                }
                if ('Purpose' in parsedSections) {
                    fields.purpose = parsedSections['Purpose'];
                }
                if ('History' in parsedSections) {
                    fields.history = parsedSections['History'];
                }
                if ('Structure' in parsedSections) {
                    fields.structure = parsedSections['Structure'];
                }
                if ('Goals' in parsedSections) {
                    fields.goals = parsedSections['Goals'];
                }

                console.debug('[GroupModal] Parsed markdown sections:', parsedSections);
            } catch (error) {
                console.warn('[GroupModal] Failed to parse markdownContent:', error);
            }
        } else if (sectionContent) {
            // Old format: apply section content
            for (const [k, v] of Object.entries(sectionContent)) { allTemplateSections[k] = v as string; }
            for (const [sectionName, content] of Object.entries(sectionContent)) {
                const propName = sectionName.toLowerCase().replace(/\s+/g, '');
                fields[propName] = content;
            }
        }

        // Apply all fields to the group
        Object.assign(this.group, fields);
        this.customFieldsEditor.setFields(this.group.customFields);
        if (Object.keys(allTemplateSections).length > 0) {
            Object.defineProperty(this.group, '_templateSections', {
                value: allTemplateSections,
                enumerable: false,
                writable: true,
                configurable: true
            });
        }
        console.debug('[GroupModal] Final group after template:', this.group);

        // Clear relationships as they reference template entities
        this.group.members = [];
        this.group.territories = [];
        this.group.linkedEvents = [];
        this.group.parentGroup = undefined;
        this.group.subgroups = [];
        this.group.groupRelationships = [];
        this.group.linkedCulture = undefined;
        this.group.connections = [];
    }

    private refresh(): void {
        void this.onOpen();
    }

    onClose() {
        this.contentEl.empty();
    }
}

/**
 * EntitySyncService - Automatically maintains bidirectional links between entities
 * Ensures that when one side of a relationship changes, the other side is updated automatically
 * 
 * Edge Cases Handled:
 * - Name vs ID mismatches: Characters use IDs for locations, Events/Items use names
 * - Case-insensitive matching: Entity lookups handle case variations
 * - Array initialization: Automatically initializes undefined arrays (e.g., character.events)
 * - Missing entities: Gracefully handles references to deleted/non-existent entities
 * - Stale references: Cleans up entityRefs when target entities are deleted
 * - Whitespace normalization: Trims and normalizes string values for comparison
 * - Circular update prevention: Uses _skipSync flag and syncInProgress tracking
 * - Entity renaming: Handles name changes by matching both old and new names
 * - Concurrent updates: Prevents infinite loops with sync tracking
 * - Empty vs undefined: Distinguishes between empty arrays and undefined fields
 */

import type StorytellerSuitePlugin from '../main';
import type { Character, Location, Event, PlotItem, Scene, EntityRef, Culture, Economy, MagicSystem, TypedRelationship } from '../types';

/**
 * Relationship mapping configuration
 */
interface RelationshipMapping {
    /** Source entity type */
    sourceType: 'character' | 'location' | 'event' | 'item' | 'scene' | 'culture' | 'economy' | 'magicsystem' | 'chapter' | 'compendiumentry';
    /** Field name on source entity */
    sourceField: string;
    /** Target entity type */
    targetType: 'character' | 'location' | 'event' | 'item' | 'scene' | 'culture' | 'economy' | 'magicsystem' | 'chapter' | 'compendiumentry';
    /** Field name on target entity */
    targetField: string;
    /** Whether this relationship is bidirectional */
    bidirectional: boolean;
    /** Whether the target field is an array (for array handling) */
    isArray?: boolean;
    /** Transform function to convert source value to target format */
    transform?: (value: any, sourceEntity: any) => any;
    /** Reverse transform for bidirectional relationships */
    reverseTransform?: (value: any, targetEntity: any) => any;
}

/**
 * Entity sync service that maintains bidirectional relationships
 */
export class EntitySyncService {
    private plugin: StorytellerSuitePlugin;
    private syncInProgress: Set<string> = new Set();
    
    constructor(plugin: StorytellerSuitePlugin) {
        this.plugin = plugin;
    }

    /**
     * Relationship mappings defining how entities are linked
     */
    private readonly relationshipMappings: RelationshipMapping[] = [
        // Character ↔ Location (currentLocationId ↔ entityRefs)
        {
            sourceType: 'character',
            sourceField: 'currentLocationId',
            targetType: 'location',
            targetField: 'entityRefs',
            bidirectional: true,
            transform: (locationId: string, character: Character) => ({
                entityId: character.id || character.name,
                entityType: 'character' as const,
                entityName: character.name,
                relationship: 'located'
            }),
            reverseTransform: (entityRef: EntityRef, location: Location) => entityRef.entityId
        },
        // Item ↔ Location (currentLocation ↔ entityRefs)
        {
            sourceType: 'item',
            sourceField: 'currentLocation',
            targetType: 'location',
            targetField: 'entityRefs',
            bidirectional: true,
            transform: (locationNameOrId: string, item: PlotItem) => ({
                entityId: item.id || item.name,
                entityType: 'item' as const,
                entityName: item.name,
                relationship: 'located'
            }),
            reverseTransform: (entityRef: EntityRef, location: Location) => {
                // Items store location as name, not ID, so return location name
                return location.name;
            }
        },
        // Event ↔ Location (location ↔ entityRefs)
        {
            sourceType: 'event',
            sourceField: 'location',
            targetType: 'location',
            targetField: 'entityRefs',
            bidirectional: true,
            transform: (locationNameOrId: string, event: Event) => ({
                entityId: event.id || event.name,
                entityType: 'event' as const,
                entityName: event.name,
                relationship: 'occurred here'
            }),
            reverseTransform: (entityRef: EntityRef, location: Location) => {
                // Events store location as name, not ID, so return location name
                return location.name;
            }
        },
        // Event ↔ Characters (characters[] ↔ events[])
        {
            sourceType: 'event',
            sourceField: 'characters',
            targetType: 'character',
            targetField: 'events',
            bidirectional: true,
            isArray: true,
            transform: (characterName: string, event: Event) => {
                // Character.events stores event names, so return event name
                return event.name || event.id || '';
            },
            reverseTransform: (eventName: string, character: Character) => {
                // Event.characters stores character names, so return character name
                return character.name || character.id || '';
            }
        },
        // Item ↔ Character (currentOwner ↔ ownedItems[])
        {
            sourceType: 'item',
            sourceField: 'currentOwner',
            targetType: 'character',
            targetField: 'ownedItems',
            bidirectional: true,
            isArray: true,
            transform: (ownerName: string, item: PlotItem) => item.name,
            reverseTransform: (itemId: string, character: Character) => character.name
        },
        // Event ↔ Item (items[] ↔ associatedEvents[])
        {
            sourceType: 'event',
            sourceField: 'items',
            targetType: 'item',
            targetField: 'associatedEvents',
            bidirectional: true,
            isArray: true,
            transform: (itemId: string, event: Event) => event.name,
            reverseTransform: (eventId: string, item: PlotItem) => item.name
        },
        // Culture → Location (linkedLocations[] → location.entityRefs) — one-way only
        // Reverse direction (location.cultures ↔ culture.linkedLocations) is handled by the mapping below
        {
            sourceType: 'culture',
            sourceField: 'linkedLocations',
            targetType: 'location',
            targetField: 'entityRefs',
            bidirectional: false,
            transform: (locationId: string, culture: Culture) => ({
