            isArray: true,
            transform: (charId: string, scene: Scene) => scene.name,
            reverseTransform: (sceneId: string, character: any) => character.name
        },
        // Scene ↔ Event (linkedEvents[] ↔ linkedScenes[])
        {
            sourceType: 'scene',
