        if (!this.canvasEl) return;
        
        const emptyState = this.canvasEl.createDiv('storyteller-network-empty-state');
        this.setParsedHtml(emptyState, `
            <div style="text-align: center; padding: 3rem;">
                <div style="font-size: 3rem; margin-bottom: 1rem; opacity: 0.3;">📊</div>
                <div style="font-size: 1.2rem; font-weight: 600; margin-bottom: 0.5rem;">No entities to display</div>
                <div style="margin-bottom: 1rem;">Create characters, locations, events, or items to see them in the network graph.</div>
                <div style="font-size: 0.9rem; color: var(--text-faint);">
                    Add relationships between entities to see connections visualized here.
                </div>
            </div>
        `);
    }

    // Search and highlight nodes
    searchAndHighlight(searchTerm: string): void {
        if (!this.cy) return;

        // Clear previous search
        this.cy.elements().removeClass('highlighted dimmed');

        if (!searchTerm) return;

        const term = searchTerm.toLowerCase();
        let found = false;

        this.cy.nodes().forEach(node => {
            const label = node.data('label').toLowerCase();
            if (label.includes(term)) {
                node.addClass('highlighted');
                found = true;
            } else {
                node.addClass('dimmed');
            }
        });

        this.cy.edges().forEach(edge => {
            const source = edge.source();
            const target = edge.target();
            if (source.hasClass('highlighted') && target.hasClass('highlighted')) {
                edge.addClass('highlighted');
            } else {
                edge.addClass('dimmed');
            }
        });

        // Fit to highlighted nodes
        if (found) {
            const highlighted = this.cy.nodes('.highlighted');
            this.cy.fit(highlighted, 50);
        }
    }

    // Clear search highlighting
    clearSearch(): void {
        if (!this.cy) return;
        this.cy.elements().removeClass('highlighted dimmed');
    }

    // Toggle edge labels visibility
    toggleEdgeLabels(): void {
        if (!this.cy) return;
        
        this.showAllEdgeLabels = !this.showAllEdgeLabels;
        
        if (this.showAllEdgeLabels) {
            // Show all edge labels
            this.cy.style()
                .selector('edge')
                .style({
                    'label': 'data(label)'
                })
                .update();
        } else {
            // Hide edge labels (only show on highlighted)
            this.cy.style()
                .selector('edge')
                .style({
                    'label': ''
                })
                .update();
        }
    }

    // Zoom controls
    zoomIn(): void {
        if (!this.cy) return;
        const currentZoom = this.cy.zoom();
        this.cy.zoom({
            level: currentZoom * 1.2,
            renderedPosition: { x: this.cy.width() / 2, y: this.cy.height() / 2 }
        });
        this.saveViewportState(); // Save after zoom
    }

    zoomOut(): void {
        if (!this.cy) return;
        const currentZoom = this.cy.zoom();
        this.cy.zoom({
            level: currentZoom * 0.8,
            renderedPosition: { x: this.cy.width() / 2, y: this.cy.height() / 2 }
        });
        this.saveViewportState(); // Save after zoom
    }

    fitToView(): void {
        if (!this.cy) return;
        this.cy.fit(undefined, 80); // Increased from 50 to match layout padding
        this.saveViewportState(); // Save after fit
    }

    // Resize the graph canvas without changing zoom/pan
    resize(): void {
        if (!this.cy) return;
        this.cy.resize();
    }

    // Save current zoom and pan position to settings (debounced)
    private saveViewportState(): void {
        if (!this.cy) return;

        // Clear existing timeout
        if (this.saveViewportTimeout) {
            window.clearTimeout(this.saveViewportTimeout);
        }

        // Debounce the save operation (wait 500ms after last change)
        this.saveViewportTimeout = window.setTimeout(() => {
            if (!this.cy) return;
            const zoom = this.cy.zoom();
            const pan = this.cy.pan();

            this.plugin.settings.networkGraphZoom = zoom;
            this.plugin.settings.networkGraphPan = { x: pan.x, y: pan.y };
            void this.plugin.saveSettings();
        }, 500);
    }

    // Restore saved zoom and pan position from settings
    private restoreViewportState(): boolean {
        if (!this.cy) return false;

        const savedZoom = this.plugin.settings.networkGraphZoom;
        const savedPan = this.plugin.settings.networkGraphPan;

        if (savedZoom !== undefined && savedPan !== undefined) {
            this.cy.zoom(savedZoom);
            this.cy.pan(savedPan);
            return true;
        }

        return false;
    }

    // Change layout algorithm
    changeLayout(layoutName: 'cose' | 'circle' | 'grid' | 'concentric'): void {
        if (!this.cy) return;
        
        this.currentLayout = layoutName;
        const layout = this.cy.layout(this.getLayoutOptions(layoutName));
        layout.run();
    }

    // Apply filters and refresh graph
    async applyFilters(filters: GraphFilters): Promise<void> {
        this.currentFilters = filters;
        await this.refresh();
    }

    // Refresh the graph
    async refresh(): Promise<void> {
        if (!this.cy) return;

        // Ensure container is valid and has dimensions
        if (!this.canvasEl || !this.canvasEl.isConnected) {
            throw new Error('Canvas element is not attached to DOM');
        }

        // Get container dimensions
        const width = this.canvasEl.offsetWidth;
        const height = this.canvasEl.offsetHeight;

        // Validate dimensions before proceeding
        if (width === 0 || height === 0) {
            throw new Error('Canvas element has invalid dimensions (width or height is 0)');
        }

        // Resize cytoscape to match current container dimensions
        this.cy.resize();

        const { nodes, edges } = await this.buildGraphData();

        // Calculate node degrees for dynamic sizing
        const nodeDegrees = new Map<string, number>();
        nodes.forEach(node => nodeDegrees.set(node.id, 0));
        edges.forEach(edge => {
            nodeDegrees.set(edge.source, (nodeDegrees.get(edge.source) || 0) + 1);
            nodeDegrees.set(edge.target, (nodeDegrees.get(edge.target) || 0) + 1);
        });

        // Convert to cytoscape format with degree data
        const elements = [
            ...nodes.map(node => ({
                data: {
                    id: node.id,
                    label: node.label,
                    type: node.type,
                    entityData: node.data,
                    imageUrl: node.imageUrl,
                    degree: nodeDegrees.get(node.id) || 0
                }
            })),
            ...edges.map(edge => ({
                data: {
                    id: `${edge.source}-${edge.target}-${edge.relationshipType}-${edge.label || ''}`,
                    source: edge.source,
                    target: edge.target,
                    relationshipType: edge.relationshipType,
                    label: edge.label
                }
            }))
        ];

        // Store positions of pinned nodes
        const pinnedPositions = new Map<string, any>();
        this.pinnedNodes.forEach(nodeId => {
            const node = this.cy?.getElementById(nodeId);
            if (node) {
                pinnedPositions.set(nodeId, node.position());
            }
        });

        // Update graph
        this.cy.elements().remove();
        this.cy.add(elements);

        // Restore pinned nodes
        this.pinnedNodes.forEach(nodeId => {
            const node = this.cy?.getElementById(nodeId);
            if (node && pinnedPositions.has(nodeId)) {
                node.position(pinnedPositions.get(nodeId));
                node.addClass('pinned');
                node.lock();
            }
        });

        // Run layout with current layout type
        this.cy.layout(this.getLayoutOptions(this.currentLayout)).run();
    }

    // Export graph as image
    async exportAsImage(format: 'png' | 'jpg' = 'png'): Promise<void> {
        if (!this.cy) return;

        const dataUrl = this.cy.png({
            output: 'blob',
            bg: getComputedStyle(activeDocument.body).getPropertyValue('--background-primary') || '#ffffff',
            full: true,
            scale: 2
        });

        // Create download link
        const link = activeDocument.createElement('a');
        link.download = `network-graph-${Date.now()}.${format}`;
        link.href = URL.createObjectURL(dataUrl);
        link.click();
        URL.revokeObjectURL(link.href);
    }

    // Get node count for status display
    getNodeCount(): number {
        return this.cy?.nodes().length || 0;
    }

    // Get edge count for status display
    getEdgeCount(): number {
        return this.cy?.edges().length || 0;
    }

    // Cleanup
    destroy(): void {
        // Clear any pending info panel timeout
        if (this.infoPanelTimeout) {
            window.clearTimeout(this.infoPanelTimeout);
            this.infoPanelTimeout = null;
        }

        // Clear viewport save timeout to prevent memory leaks
        if (this.saveViewportTimeout) {
            window.clearTimeout(this.saveViewportTimeout);
            this.saveViewportTimeout = null;
        }

        // Clean up info panel
        if (this.infoPanelEl) {
            this.infoPanelEl.remove();
            this.infoPanelEl = null;
        }

        // Clean up legend panel elements
        if (this.legendPanelEl) {
            this.legendPanelEl.remove();
            this.legendPanelEl = null;
        }

        if (this.legendToggleButtonEl) {
            this.legendToggleButtonEl.remove();
            this.legendToggleButtonEl = null;
        }

        // Clean up Cytoscape instance
        if (this.cy) {
            this.cy.destroy();
            this.cy = null;
        }

        // Clean up canvas element
        if (this.canvasEl) {
            this.canvasEl.remove();
            this.canvasEl = null;
        }

        this.pinnedNodes.clear();
    }
}

/**
 * WritingViewRenderers — shared render logic for the Board / Arc / Heatmap / Holes
 * writing analysis views. Used by both DashboardView (inline) and WritingPanelView
 * (standalone panel). The class holds per-instance state (kanban grouping) so
 * each view maintains its own preferences independently.
 */

import { App, TFile, Notice, setIcon } from 'obsidian';
import StorytellerSuitePlugin from '../main';

export type KanbanGroupBy = 'status' | 'chapter' | 'pov';
export type WritingPanelMode = 'board' | 'arc' | 'heatmap' | 'holes';

const EMOTION_COLORS: Record<string, string> = {
    tense: '#ef5350', joyful: '#fdd835', sorrowful: '#5c6bc0',
    mysterious: '#ab47bc', hopeful: '#66bb6a', fearful: '#8d6e63',
    angry: '#f4511e', romantic: '#ec407a', melancholic: '#78909c', neutral: '#90a4ae',
};

const STATUS_CLASS: Record<string, string> = {
    Outline: 'sts-outline', Draft: 'sts-draft', WIP: 'sts-wip',
    Revised: 'sts-revised', Final: 'sts-final',
};

export class WritingViewRenderers {
    private app: App;
    private plugin: StorytellerSuitePlugin;
    kanbanGroupBy: KanbanGroupBy = 'status';

    constructor(app: App, plugin: StorytellerSuitePlugin) {
        this.app = app;
        this.plugin = plugin;
    }

    // ── Kanban Board ──────────────────────────────────────────────────────────

    async renderKanbanBoard(container: HTMLElement, filter: string) {
        const chapters = await this.plugin.listChapters();
        const filterFn = (sc: any) =>
            !filter ||
            sc.name.toLowerCase().includes(filter) ||
            (sc.chapterName || '').toLowerCase().includes(filter) ||
            (sc.povCharacter || '').toLowerCase().includes(filter);

        const controls = container.createDiv('storyteller-kanban-controls');
        controls.createSpan({ text: 'Group by:', cls: 'storyteller-kanban-label' });

        const groupByOptions: Array<{ id: KanbanGroupBy; label: string }> = [
            { id: 'status',  label: 'Status'  },
            { id: 'chapter', label: 'Chapter' },
            { id: 'pov',     label: 'POV'     },
        ];

        let boardEl: HTMLElement | null = null;

        const reloadBoard = () => { void (async () => {
            const freshScenes = (await this.plugin.listScenes()).filter(filterFn);
            boardEl?.remove();
            boardEl = container.createDiv('storyteller-kanban-board');
            this._renderKanbanColumns(boardEl, freshScenes, chapters, this.kanbanGroupBy, reloadBoard);
        })(); };

        groupByOptions.forEach(opt => {
            const btn = controls.createEl('button', {
                text: opt.label,
                cls: `storyteller-kanban-group-btn${this.kanbanGroupBy === opt.id ? ' is-active' : ''}`,
            });
            btn.onclick = () => {
                this.kanbanGroupBy = opt.id;
                controls.querySelectorAll('.storyteller-kanban-group-btn').forEach(b => b.removeClass('is-active'));
                btn.addClass('is-active');
                void reloadBoard();
            };
        });

        reloadBoard();
    }

    private _renderKanbanColumns(
        board: HTMLElement,
        scenes: any[],
        chapters: any[],
        groupBy: KanbanGroupBy,
        rerender?: () => void,
    ) {
        board.empty();
        const groups = new Map<string, any[]>();

        if (groupBy === 'status') {
            ['Outline', 'Draft', 'WIP', 'Revised', 'Final', '(none)'].forEach(s => groups.set(s, []));
            scenes.forEach(sc => {
                const key = sc.status || '(none)';
                if (!groups.has(key)) groups.set(key, []);
                groups.get(key)!.push(sc);
            });
        } else if (groupBy === 'chapter') {
            [...chapters].sort((a, b) => (a.number ?? 999) - (b.number ?? 999))
                .forEach(ch => groups.set(ch.name || ch.id, []));
            groups.set('(unassigned)', []);
            scenes.forEach(sc => {
                const key = sc.chapterName || '(unassigned)';
                if (!groups.has(key)) groups.set(key, []);
                groups.get(key)!.push(sc);
            });
        } else {
            groups.set('(no POV)', []);
            scenes.forEach(sc => {
                const key = sc.povCharacter || '(no POV)';
                if (!groups.has(key)) groups.set(key, []);
                groups.get(key)!.push(sc);
            });
        }

        const chapterByName = new Map<string, any>(chapters.map(ch => [ch.name || ch.id, ch]));

        groups.forEach((groupScenes, groupName) => {
            if (groupScenes.length === 0 && groupBy !== 'status') return;

            const col = board.createDiv('storyteller-kanban-col');

            // Apply status color class to column
            if (groupBy === 'status' && groupName !== '(none)') {
                const sc = STATUS_CLASS[groupName];
                if (sc) col.addClass(`storyteller-kanban-col-${sc}`);
            }

            const hdr = col.createDiv('storyteller-kanban-col-header');
            hdr.createSpan({ text: groupName, cls: 'storyteller-kanban-col-title' });
            hdr.createSpan({ text: String(groupScenes.length), cls: 'storyteller-kanban-col-count' });

            if (groupBy === 'chapter' && chapterByName.has(groupName)) {
                const ch = chapterByName.get(groupName)!;
                const editBtn = hdr.createEl('button', { cls: 'storyteller-kanban-col-edit-btn' });
                setIcon(editBtn, 'pencil');
                editBtn.title = `Edit chapter "${groupName}"`;
                editBtn.onclick = () => {
                    void import('../modals/ChapterModal').then(({ ChapterModal }) => {
                        new ChapterModal(this.app, this.plugin, ch, async (updated: any) => {
                            await this.plugin.saveChapter(updated);
                            new Notice(`Chapter "${updated.name}" updated.`);
                        }, async (toDelete: any) => {
                            if (toDelete.filePath) await this.plugin.deleteChapter(toDelete.filePath);
                        }).open();
                    });
                };
            }

            const body = col.createDiv('storyteller-kanban-col-body');
            body.setAttr('data-group', groupName);

            // Drop-zone handlers
            body.addEventListener('dragover', (e) => {
                e.preventDefault();
                if (e.dataTransfer) e.dataTransfer.dropEffect = 'move';
            });
            body.addEventListener('dragenter', (e) => {
                e.preventDefault();
                body.addClass('storyteller-kanban-drop-over');
            });
            body.addEventListener('dragleave', (e) => {
                if (!body.contains(e.relatedTarget as Node)) {
                    body.removeClass('storyteller-kanban-drop-over');
                }
            });
            body.addEventListener('drop', (e) => { void (async () => {
                e.preventDefault();
                body.removeClass('storyteller-kanban-drop-over');
                try {
                    const raw = e.dataTransfer?.getData('text/plain');
                    if (!raw) return;
                    const data = JSON.parse(raw);
                    const sc = scenes.find((s: any) => s.filePath === data.filePath);
                    if (!sc) return;
                    const updated = { ...sc };
                    if (groupBy === 'status') {
                        updated.status = groupName !== '(none)' ? groupName : undefined;
                    } else if (groupBy === 'chapter') {
                        const ch = chapterByName.get(groupName);
                        if (ch) {
                            updated.chapterId = ch.id;
                            updated.chapterName = ch.name;
                        } else {
                            updated.chapterId = undefined;
                            updated.chapterName = undefined;
                        }
                    } else {
                        updated.povCharacter = groupName !== '(no POV)' ? groupName : undefined;
                    }
                    await this.plugin.saveScene(updated);
                    if (rerender) rerender();
                } catch { /* ignore parse/save errors */ }
            })(); });

            if (groupScenes.length === 0) {
                body.createDiv({ cls: 'storyteller-kanban-empty', text: 'No scenes' });
            } else {
                groupScenes.forEach(sc => this._renderKanbanCard(body, sc, groupBy));
            }
        });
    }

    private _renderKanbanCard(col: HTMLElement, sc: any, groupBy?: KanbanGroupBy) {
        const card = col.createDiv('storyteller-kanban-card');

        // Status color on card border-left
        const statusKey = sc.status && STATUS_CLASS[sc.status] ? `storyteller-kanban-card-${STATUS_CLASS[sc.status]}` : null;
        if (statusKey) card.addClass(statusKey);

        // Drag and drop
        card.setAttr('draggable', 'true');
        card.addEventListener('dragstart', (e) => {
            if (e.dataTransfer) {
                e.dataTransfer.setData('text/plain', JSON.stringify({ filePath: sc.filePath }));
                e.dataTransfer.effectAllowed = 'move';
            }
            card.addClass('storyteller-kanban-card-dragging');
        });
        card.addEventListener('dragend', () => {
            card.removeClass('storyteller-kanban-card-dragging');
        });

        const title = card.createEl('strong', { text: sc.name, cls: 'storyteller-kanban-card-title' });
        title.addEventListener('click', () => {
            if (sc.filePath) {
                const f = this.app.vault.getAbstractFileByPath(sc.filePath);
                if (f instanceof TFile) void this.app.workspace.openLinkText(sc.filePath, '', false);
            }
        });

        const meta = card.createDiv('storyteller-kanban-card-meta');
        if (sc.chapterName && groupBy !== 'chapter') {
            meta.createSpan({ text: sc.chapterName, cls: 'storyteller-kanban-chapter-label' });
        }
        if (sc.povCharacter && groupBy !== 'pov') {
            const pov = meta.createSpan({ cls: 'storyteller-scene-pov-badge' });
            setIcon(pov.createSpan(''), 'eye');
            pov.createSpan({ text: ` ${sc.povCharacter}` });
        }
        if (sc.emotion) {
            meta.createSpan({ text: sc.emotion, cls: `storyteller-scene-emotion-chip storyteller-emotion-${sc.emotion}` });
        }

        if (sc.intensity !== undefined && sc.intensity !== null) {
            const barWrap = card.createDiv('storyteller-intensity-mini');
            const fill = barWrap.createDiv('storyteller-intensity-fill');
            fill.setCssStyles({ width: `${Math.round(((Number(sc.intensity) + 10) / 20) * 100)}%` });
            fill.title = `Intensity: ${sc.intensity}`;
        }

        const actions = card.createDiv('storyteller-kanban-card-actions');

        const editBtn = actions.createEl('button', { cls: 'storyteller-kanban-action-btn' });
        setIcon(editBtn, 'pencil');
        editBtn.title = 'Edit scene';
        editBtn.onclick = () => {
            void import('../modals/SceneModal').then(({ SceneModal }) => {
                new SceneModal(this.app, this.plugin, sc, async (updated) => {
                    await this.plugin.saveScene(updated);
                    new Notice(`Scene "${updated.name}" updated.`);
                }, async (toDelete) => {
                    if (toDelete.filePath) await this.plugin.deleteScene(toDelete.filePath);
                }).open();
            });
        };

        const openBtn = actions.createEl('button', { cls: 'storyteller-kanban-action-btn' });
        setIcon(openBtn, 'file-text');
        openBtn.title = 'Open note';
        openBtn.onclick = () => {
            if (sc.filePath) {
                const f = this.app.vault.getAbstractFileByPath(sc.filePath);
                if (f instanceof TFile) void this.app.workspace.openLinkText(sc.filePath, '', false);
            }
        };
    }

    // ── Arc Chart ─────────────────────────────────────────────────────────────

    async renderArcChart(container: HTMLElement) {
        const allScenes = await this.plugin.listScenes();
        const chapters = (await this.plugin.listChapters()).sort((a, b) => (a.number ?? 999) - (b.number ?? 999));

        if (allScenes.length === 0) {
            container.createEl('p', { text: 'No scenes yet — create some to see the arc.', cls: 'u-muted' });
            return;
        }

        const chapterOrder = new Map(chapters.map(ch => [ch.id || ch.name, ch.number ?? 999]));
        const sorted = [...allScenes].sort((a, b) => {
            const ao = chapterOrder.get(a.chapterId || a.chapterName || '') ?? 999;
            const bo = chapterOrder.get(b.chapterId || b.chapterName || '') ?? 999;
            if (ao !== bo) return ao - bo;
            return (a.name || '').localeCompare(b.name || '');
        });

        const W = 720, H = 280;
        const PAD = { top: 28, right: 28, bottom: 52, left: 42 };
        const iW = W - PAD.left - PAD.right;
        const iH = H - PAD.top - PAD.bottom;
        const n = sorted.length;
        const svgNS = 'http://www.w3.org/2000/svg';

        const wrapper = container.createDiv('storyteller-arc-wrapper');
        wrapper.createEl('h4', { text: 'Intensity arc', cls: 'storyteller-arc-title' });

        const svg = activeDocument.createElementNS(svgNS, 'svg');
        svg.setAttribute('viewBox', `0 0 ${W} ${H}`);
        svg.setAttribute('width', '100%');
        svg.setAttribute('height', String(H));
        svg.classList.add('storyteller-arc-svg');
        wrapper.appendChild(svg);

        // ── Defs: gradient ──
        const defs = activeDocument.createElementNS(svgNS, 'defs');
        const grad = activeDocument.createElementNS(svgNS, 'linearGradient');
        grad.setAttribute('id', 'sts-arc-area-grad');
        grad.setAttribute('x1', '0'); grad.setAttribute('y1', '0');
        grad.setAttribute('x2', '0'); grad.setAttribute('y2', '1');
        const stop1 = activeDocument.createElementNS(svgNS, 'stop');
        stop1.setAttribute('offset', '0%');
        stop1.setAttribute('stop-color', 'var(--interactive-accent)');
        stop1.setAttribute('stop-opacity', '0.28');
        const stop2 = activeDocument.createElementNS(svgNS, 'stop');
        stop2.setAttribute('offset', '100%');
        stop2.setAttribute('stop-color', 'var(--interactive-accent)');
        stop2.setAttribute('stop-opacity', '0');
        grad.appendChild(stop1); grad.appendChild(stop2);
        defs.appendChild(grad);
        svg.appendChild(defs);

        const g = activeDocument.createElementNS(svgNS, 'g');
        g.setAttribute('transform', `translate(${PAD.left},${PAD.top})`);
        svg.appendChild(g);

        const zeroY = iH / 2;

        const makeLine = (x1: number, y1: number, x2: number, y2: number, stroke: string, dash?: string, opacity?: number) => {
            const l = activeDocument.createElementNS(svgNS, 'line');
            l.setAttribute('x1', String(x1)); l.setAttribute('y1', String(y1));
            l.setAttribute('x2', String(x2)); l.setAttribute('y2', String(y2));
            l.setAttribute('stroke', stroke);
            if (dash) l.setAttribute('stroke-dasharray', dash);
            if (opacity !== undefined) l.setAttribute('opacity', String(opacity));
            return l;
        };

        // ── Chapter bands (alternating background) ──
        chapters.forEach((ch, ci) => {
            const chScenes = sorted.filter(sc => sc.chapterId === ch.id || sc.chapterName === ch.name);
            if (chScenes.length === 0) return;
            const firstIdx = sorted.indexOf(chScenes[0]);
            const lastIdx = sorted.indexOf(chScenes[chScenes.length - 1]);
            const x1 = n <= 1 ? 0 : (firstIdx / (n - 1)) * iW;
            const rawX2 = n <= 1 ? iW : (lastIdx / (n - 1)) * iW + (n > 1 ? iW / (n - 1) : iW);
            const x2 = Math.min(rawX2, iW);
            if (ci % 2 === 1) {
                const band = activeDocument.createElementNS(svgNS, 'rect');
                band.setAttribute('x', x1.toFixed(1));
                band.setAttribute('y', '0');
                band.setAttribute('width', Math.max(0, x2 - x1).toFixed(1));
                band.setAttribute('height', String(iH));
                band.setAttribute('fill', 'rgba(255,255,255,0.035)');
                g.appendChild(band);
            }
        });

        // ── Grid lines ──
        g.appendChild(makeLine(0, zeroY, iW, zeroY, 'var(--background-modifier-border)', '4,3'));
        [-5, 5].forEach(val => {
            const y = iH / 2 - (val / 10) * (iH / 2);
            g.appendChild(makeLine(0, y, iW, y, 'var(--background-modifier-border)', '2,4', 0.5));
        });

        // ── Y-axis labels ──
        [10, 5, 0, -5, -10].forEach(val => {
            const y = iH / 2 - (val / 10) * (iH / 2);
            const t = activeDocument.createElementNS(svgNS, 'text');
            t.setAttribute('x', '-6'); t.setAttribute('y', String(y + 4));
            t.setAttribute('text-anchor', 'end');
            t.setAttribute('font-size', '9');
            t.setAttribute('fill', 'var(--text-muted)');
            t.textContent = String(val);
            g.appendChild(t);
        });

        const pts = sorted.map((sc, i) => {
            const x = n <= 1 ? iW / 2 : (i / (n - 1)) * iW;
            const iv = sc.intensity !== undefined && sc.intensity !== null ? Number(sc.intensity) : 0;
            const y = iH / 2 - (iv / 10) * (iH / 2);
            return { x, y, sc };
        });

        // ── Catmull-Rom bezier path ──
        const catmullRomPath = (points: { x: number; y: number }[]) => {
            if (points.length < 2) return '';
            const parts = [`M ${points[0].x.toFixed(1)} ${points[0].y.toFixed(1)}`];
            for (let i = 0; i < points.length - 1; i++) {
                const p0 = points[Math.max(i - 1, 0)];
                const p1 = points[i];
                const p2 = points[i + 1];
                const p3 = points[Math.min(i + 2, points.length - 1)];
                const cp1x = p1.x + (p2.x - p0.x) / 6;
                const cp1y = p1.y + (p2.y - p0.y) / 6;
                const cp2x = p2.x - (p3.x - p1.x) / 6;
                const cp2y = p2.y - (p3.y - p1.y) / 6;
                parts.push(`C ${cp1x.toFixed(1)} ${cp1y.toFixed(1)}, ${cp2x.toFixed(1)} ${cp2y.toFixed(1)}, ${p2.x.toFixed(1)} ${p2.y.toFixed(1)}`);
            }
            return parts.join(' ');
        };

        if (pts.length > 1) {
            const curvePath = catmullRomPath(pts);
            const first = pts[0], last = pts[pts.length - 1];

            // Area fill (gradient)
            const areaPath = activeDocument.createElementNS(svgNS, 'path');
            areaPath.setAttribute('d', `${curvePath} L ${last.x.toFixed(1)} ${zeroY} L ${first.x.toFixed(1)} ${zeroY} Z`);
            areaPath.setAttribute('fill', 'url(#sts-arc-area-grad)');
            areaPath.setAttribute('stroke', 'none');
            g.appendChild(areaPath);

            // Line
            const linePath = activeDocument.createElementNS(svgNS, 'path');
            linePath.setAttribute('d', curvePath);
            linePath.setAttribute('fill', 'none');
            linePath.setAttribute('stroke', 'var(--interactive-accent)');
            linePath.setAttribute('stroke-width', '2.5');
            linePath.setAttribute('opacity', '0.75');
            g.appendChild(linePath);
        }

        // ── Chapter tick marks ──
        chapters.forEach(ch => {
            const chScenes = sorted.filter(sc => sc.chapterId === ch.id || sc.chapterName === ch.name);
            if (chScenes.length === 0) return;
            const firstIdx = sorted.indexOf(chScenes[0]);
            const x = n <= 1 ? iW / 2 : (firstIdx / (n - 1)) * iW;
            g.appendChild(makeLine(x, iH + 2, x, iH + 8, 'var(--text-muted)'));
            const lbl = activeDocument.createElementNS(svgNS, 'text');
            lbl.setAttribute('x', x.toFixed(1));
            lbl.setAttribute('y', String(iH + 20));
            lbl.setAttribute('text-anchor', 'middle');
            lbl.setAttribute('font-size', '9');
            lbl.setAttribute('fill', 'var(--text-muted)');
            lbl.textContent = `Ch.${ch.number ?? '?'}`;
            g.appendChild(lbl);
        });

        // ── Data points (on top, after area fill) ──
        pts.forEach(({ x, y, sc }) => {
            const color = sc.emotion ? (EMOTION_COLORS[sc.emotion] || '#90a4ae') : 'var(--text-muted)';
            const circle = activeDocument.createElementNS(svgNS, 'circle');
            circle.setAttribute('cx', x.toFixed(1));
            circle.setAttribute('cy', y.toFixed(1));
            circle.setAttribute('r', '7');
            circle.setAttribute('fill', color);
            circle.setAttribute('stroke', 'var(--background-primary)');
            circle.setAttribute('stroke-width', '2');
            if (sc.emotion) {
                circle.setAttribute('filter', `drop-shadow(0 0 4px ${color})`);
            }
            circle.classList.add('storyteller-arc-dot');
            const tip = activeDocument.createElementNS(svgNS, 'title');
            tip.textContent = sc.name +
                (sc.intensity !== undefined ? ` · intensity ${sc.intensity}` : '') +
                (sc.emotion ? ` · ${sc.emotion}` : '');
            circle.appendChild(tip);
            g.appendChild(circle);
        });

        // ── Emotion stats row ──
        const emotionCounts: Record<string, number> = {};
        sorted.forEach(sc => { if (sc.emotion) emotionCounts[sc.emotion] = (emotionCounts[sc.emotion] || 0) + 1; });
        if (Object.keys(emotionCounts).length > 0) {
            const statsRow = wrapper.createDiv('storyteller-arc-stats');
            Object.entries(emotionCounts).sort(([, a], [, b]) => b - a).forEach(([emotion, count]) => {
                const color = EMOTION_COLORS[emotion] || '#90a4ae';
                const chip = statsRow.createSpan({ cls: 'storyteller-arc-stat-chip' });
                chip.setCssStyles({ background: color + '22' });
                chip.setCssStyles({ color: color });
                const dot = chip.createSpan({ cls: 'storyteller-arc-stat-dot' });
                dot.setCssStyles({ background: color });
                chip.createSpan({ text: `${emotion} ×${count}` });
            });
        }

        // ── Legend ──
        const legend = wrapper.createDiv('storyteller-arc-legend');
        Object.entries(EMOTION_COLORS).forEach(([emotion, color]) => {
            const item = legend.createDiv('storyteller-arc-legend-item');
            const dot = item.createSpan({ cls: 'storyteller-arc-legend-dot' });
            dot.setCssStyles({ background: color });
            item.createSpan({ text: emotion, cls: 'storyteller-arc-legend-label' });
        });
    }

    // ── Heatmap ───────────────────────────────────────────────────────────────

    async renderHeatmap(container: HTMLElement) {
        const scenes = await this.plugin.listScenes();
        const chapters = (await this.plugin.listChapters()).sort((a, b) => (a.number ?? 999) - (b.number ?? 999));
        const characters = await this.plugin.listCharacters();

        if (scenes.length === 0 || characters.length === 0) {
            container.createEl('p', { text: 'Need scenes with linked characters to generate heatmap.', cls: 'u-muted' });
            return;
        }

        const canonicalByLower = new Map<string, string>();
        characters.forEach(c => {
            if (c.name) canonicalByLower.set(c.name.trim().toLowerCase(), c.name);
        });
        const resolveCanonical = (raw: string): string | undefined => {
            if (typeof raw !== 'string') return undefined;
            return canonicalByLower.get(raw.trim().toLowerCase());
        };

        const appearsInScenes = new Set<string>();
        scenes.forEach(sc => (sc.linkedCharacters || []).forEach((n: string) => {
            const canonical = resolveCanonical(n);
            if (canonical) appearsInScenes.add(canonical);
        }));
        const activeChars = characters.map(c => c.name).filter(n => n && appearsInScenes.has(n)).slice(0, 20);

        if (activeChars.length === 0) {
            container.createEl('p', { text: 'No character links found in scenes yet.', cls: 'u-muted' });
            return;
        }

        const heat = new Map<string, Map<string, number>>();
        activeChars.forEach(n => heat.set(n, new Map()));
        scenes.forEach(sc => {
            const chKey = sc.chapterName || sc.chapterId || '(unassigned)';
            (sc.linkedCharacters || []).forEach((n: string) => {
                const canonical = resolveCanonical(n);
                if (!canonical || !heat.has(canonical)) return;
                const row = heat.get(canonical)!;
                row.set(chKey, (row.get(chKey) || 0) + 1);
            });
        });

        const colKeys = chapters.map(ch => ch.name);
        if (scenes.some(sc => !sc.chapterName && !sc.chapterId)) colKeys.push('(unassigned)');

        let maxCount = 1;
        heat.forEach(row => row.forEach(v => { if (v > maxCount) maxCount = v; }));

        const wrapper = container.createDiv('storyteller-heatmap-wrapper');
        wrapper.createEl('h4', { text: 'Character presence', cls: 'storyteller-heatmap-title' });

        const scroll = wrapper.createDiv('storyteller-heatmap-scroll');
        const table = scroll.createEl('table', { cls: 'storyteller-heatmap-table' });

        const thead = table.createEl('thead');
        const hrow = thead.createEl('tr');
        hrow.createEl('th', { text: 'Character', cls: 'storyteller-heatmap-char-header' });
        colKeys.forEach((key, i) => {
            const ch = chapters[i];
            const th = hrow.createEl('th', { cls: 'storyteller-heatmap-chapter-header' });
            th.title = key;
            th.textContent = ch ? `Ch.${ch.number ?? i + 1}` : key;
        });

        const tbody = table.createEl('tbody');
        activeChars.forEach(charName => {
            const tr = tbody.createEl('tr');
            tr.createEl('td', { text: charName, cls: 'storyteller-heatmap-char-label' });
            colKeys.forEach(key => {
                const count = heat.get(charName)?.get(key) || 0;
                const td = tr.createEl('td', { cls: 'storyteller-heatmap-cell' });
                if (count > 0) {
                    const alpha = (0.18 + (count / maxCount) * 0.72).toFixed(2);
                    // Green heatmap cells
                    td.setCssStyles({ background: `rgba(74,222,128,${alpha})` });
                    td.setCssStyles({ color: Number(alpha) > 0.55 ? '#0a2a14' : 'rgba(255,255,255,0.9)' });
                    td.title = `${charName} · ${key}: ${count} scene${count !== 1 ? 's' : ''}`;
                    td.textContent = String(count);
                }
            });
        });
    }

    // ── Plot Holes ────────────────────────────────────────────────────────────

    async renderPlotHoles(container: HTMLElement) {
        const scenes = await this.plugin.listScenes();
        const characters = await this.plugin.listCharacters();
        const charNames = new Set(characters.map(c => c.name).filter(Boolean));

        const issues: Array<{ severity: 'warning' | 'info'; title: string; detail: string }> = [];

        const unassigned = scenes.filter(sc => !sc.chapterId && !sc.chapterName);
        if (unassigned.length > 0) {
            issues.push({ severity: 'warning',
                title: `${unassigned.length} scene${unassigned.length !== 1 ? 's' : ''} not assigned to a chapter`,
                detail: unassigned.map(sc => sc.name).join(', ') });
        }

        const setupNoPayoff = scenes.filter(sc =>
            (sc.setupScenes || []).length > 0 && (sc.payoffScenes || []).length === 0);
        if (setupNoPayoff.length > 0) {
            issues.push({ severity: 'warning',
                title: `${setupNoPayoff.length} scene${setupNoPayoff.length !== 1 ? 's' : ''} foreshadow other scenes but have no recorded payoff`,
                detail: setupNoPayoff.map((sc: any) => sc.name).join(', ') });
        }

        const payoffNoSetup = scenes.filter(sc =>
            (sc.payoffScenes || []).length > 0 && (sc.setupScenes || []).length === 0);
        if (payoffNoSetup.length > 0) {
            issues.push({ severity: 'info',
                title: `${payoffNoSetup.length} scene${payoffNoSetup.length !== 1 ? 's' : ''} pay off other scenes without any foreshadowing`,
                detail: payoffNoSetup.map((sc: any) => sc.name).join(', ') });
        }

        const unknownRefs: string[] = [];
        scenes.forEach((sc: any) => {
            (sc.linkedCharacters || []).forEach((n: string) => {
                const entry = `"${n}" in "${sc.name}"`;
                if (!charNames.has(n) && !unknownRefs.includes(entry)) unknownRefs.push(entry);
            });
        });
        if (unknownRefs.length > 0) {
            issues.push({ severity: 'warning',
                title: `${unknownRefs.length} character reference${unknownRefs.length !== 1 ? 's' : ''} in scenes don't match any character file`,
                detail: unknownRefs.join('; ') });
        }

        const noLocation = scenes.filter((sc: any) => (sc.linkedLocations || []).length === 0);
        if (noLocation.length > 0) {
            issues.push({ severity: 'info',
                title: `${noLocation.length} scene${noLocation.length !== 1 ? 's' : ''} have no linked location`,
                detail: noLocation.map(sc => sc.name).join(', ') });
        }

        const emptyContent = scenes.filter(sc => !sc.content?.trim());
        if (emptyContent.length > 0) {
            issues.push({ severity: 'info',
                title: `${emptyContent.length} scene${emptyContent.length !== 1 ? 's' : ''} have no written content`,
                detail: emptyContent.map(sc => sc.name).join(', ') });
        }

        const hdr = container.createDiv('storyteller-holes-header');
        hdr.createEl('h4', { text: 'Plot hole detector', cls: 'storyteller-holes-title' });

        if (issues.length === 0) {
            hdr.remove();
            const clear = container.createDiv('storyteller-holes-clear');
            setIcon(clear.createSpan({ cls: 'storyteller-holes-clear-icon' }), 'check-circle');
            clear.createSpan({ text: 'No issues detected — your plot looks airtight!' });
            return;
        }

        hdr.createSpan({ text: `${issues.length} issue${issues.length !== 1 ? 's' : ''} detected`, cls: 'storyteller-holes-count' });

        const list = container.createDiv('storyteller-holes-list');
        issues.forEach(issue => {
            const card = list.createDiv(`storyteller-holes-card storyteller-holes-${issue.severity}`);
            const titleRow = card.createDiv('storyteller-holes-card-title');
            setIcon(titleRow.createSpan({ cls: 'storyteller-holes-icon' }), issue.severity === 'warning' ? 'alert-triangle' : 'info');
            titleRow.createSpan({ text: issue.title });
            card.createEl('p', { text: issue.detail, cls: 'storyteller-holes-detail' });
        });
    }
}

import { App, ButtonComponent, TFile, setIcon } from 'obsidian';
import type StorytellerSuitePlugin from '../../../main';

interface WritingListRendererContext {
    app: App;
    plugin: StorytellerSuitePlugin;
    currentFilter: string;
    chapterCollapseState: Map<string, boolean>;
    getImageSrc(imagePath: string): string;
    addEditButton(container: HTMLElement, onClick: () => void): void;
    addDeleteButton(container: HTMLElement, onClick: () => Promise<void>): void;
    addOpenFileButton(container: HTMLElement, filePath: string | undefined): ButtonComponent | null;
    persistChapter(chapter: any, successNotice: string, detail: string): Promise<void>;
    persistScene(scene: any, successNotice: string, detail: string): Promise<void>;
    removeChapter(filePath: string, detail: string): Promise<void>;
    removeScene(filePath: string, detail: string): Promise<void>;
    confirmDeleteChapter(filePath: string, chapterName: string, detail: string): Promise<void>;
    confirmDeleteScene(filePath: string, sceneName: string, detail: string): Promise<void>;
}

export async function renderWritingChapterSceneList(container: HTMLElement, context: WritingListRendererContext): Promise<void> {
    const existingListContainer = container.querySelector('.storyteller-list-container');
    if (existingListContainer) {
        existingListContainer.remove();
    }

    const chapters = (await context.plugin.listChapters()).filter(ch =>
        ch.name.toLowerCase().includes(context.currentFilter) ||
        (`${ch.number ?? ''}`).toLowerCase().includes(context.currentFilter) ||
        (ch.summary || '').toLowerCase().includes(context.currentFilter) ||
        (ch.tags || []).join(' ').toLowerCase().includes(context.currentFilter)
    );

    const allScenes = await context.plugin.listScenes();

    const listContainer = container.createDiv('storyteller-list-container');
    if (chapters.length === 0) {
        listContainer.createEl('p', { text: `No chapters found.${context.currentFilter ? ' Matching current filter.' : ''}` });
        return;
    }

    chapters.sort((a, b) => (a.number ?? 999) - (b.number ?? 999));

    chapters.forEach(chapter => {
        const chapterGroup = listContainer.createDiv('storyteller-chapter-group');
        const chapterHeader = chapterGroup.createDiv('storyteller-chapter-header');

        const toggleButton = chapterHeader.createDiv('storyteller-chapter-toggle');
        setIcon(toggleButton, 'chevron-down');

        const pfpContainer = chapterHeader.createDiv('storyteller-list-item-pfp');
        if (chapter.profileImagePath) {
            const image = pfpContainer.createEl('img');
            try {
                image.src = context.getImageSrc(chapter.profileImagePath);
                image.alt = chapter.name;
            } catch {
                pfpContainer.createSpan({ text: '?' });
            }
        } else {
            const badge = pfpContainer.createDiv({ cls: 'storyteller-pfp-placeholder', text: (chapter.number ?? '?').toString() });
            badge.title = 'Chapter number';
        }

        const infoEl = chapterHeader.createDiv('storyteller-list-item-info');
        const title = chapter.number != null ? `Chapter ${chapter.number}: ${chapter.name}` : chapter.name;
        const chapterScenes = allScenes.filter(scene => scene.chapterId === chapter.id || scene.chapterName === chapter.name);

        const titleRow = infoEl.createDiv('storyteller-chapter-title-row');
        const chapterTitle = titleRow.createEl('strong', { text: title });
        if (chapter.filePath) {
            chapterTitle.addClass('storyteller-chapter-name-link');
            chapterTitle.title = 'Click to open note';
            chapterTitle.addEventListener('click', event => {
                event.stopPropagation();
                const file = context.app.vault.getAbstractFileByPath(chapter.filePath!);
                if (file instanceof TFile) {
                    void context.app.workspace.openLinkText(chapter.filePath!, '', false);
                }
            });
        }

        const inlineEditButton = titleRow.createEl('button', { cls: 'storyteller-chapter-inline-edit' });
        setIcon(inlineEditButton, 'pencil');
        inlineEditButton.title = 'Edit chapter';
        inlineEditButton.addEventListener('click', event => {
            event.stopPropagation();
            void import('../../../modals/ChapterModal').then(({ ChapterModal }) => {
                new ChapterModal(context.app, context.plugin, chapter, async (updated) => {
                    await context.persistChapter(updated, `Chapter "${updated.name}" updated.`, 'writing-inline-chapter-updated');
                }, async (toDelete) => {
                    if (toDelete.filePath) {
                        await context.removeChapter(toDelete.filePath, 'writing-inline-chapter-deleted');
                    }
                }).open();
            });
        });

        titleRow.createSpan({ cls: 'storyteller-chapter-scene-count', text: `${chapterScenes.length} scene${chapterScenes.length !== 1 ? 's' : ''}` });
        if (chapter.bookName) {
            titleRow.createSpan({ cls: 'storyteller-meta-badge storyteller-book-badge', text: chapter.bookName });
        }

        if (chapter.summary) {
            const preview = chapter.summary.length > 100 ? `${chapter.summary.substring(0, 100)}...` : chapter.summary;
            infoEl.createEl('p', { text: preview, cls: 'storyteller-chapter-summary' });
        }

        const actionsEl = chapterHeader.createDiv('storyteller-list-item-actions');
        context.addEditButton(actionsEl, () => {
            void import('../../../modals/ChapterModal').then(({ ChapterModal }) => {
                new ChapterModal(context.app, context.plugin, chapter, async (updated) => {
                    await context.persistChapter(updated, `Chapter "${updated.name}" updated.`, 'writing-chapter-updated');
                }, async (toDelete) => {
                    if (toDelete.filePath) {
                        await context.removeChapter(toDelete.filePath, 'writing-chapter-deleted-from-modal');
                    }
                }).open();
            });
        });
        context.addDeleteButton(actionsEl, async () => {
            if (chapter.filePath) {
                await context.confirmDeleteChapter(chapter.filePath, chapter.name, 'writing-chapter-deleted');
            }
        });
        context.addOpenFileButton(actionsEl, chapter.filePath);

        const scenesContainer = chapterGroup.createDiv('storyteller-chapter-scenes');
        if (chapterScenes.length === 0) {
            scenesContainer.createEl('p', { cls: 'storyteller-no-scenes', text: 'No scenes in this chapter' });
        } else {
            chapterScenes.forEach(scene => {
                renderWritingSceneItem(scenesContainer, scene, true, context);
            });
        }

        const addSceneButton = scenesContainer.createDiv('storyteller-add-scene-btn');
        setIcon(addSceneButton.createSpan(), 'plus');
        addSceneButton.createSpan({ text: ' Add scene to this chapter' });
        addSceneButton.onclick = () => {
            void import('../../../modals/SceneModal').then(({ SceneModal }) => {
                const newScene = { chapterId: chapter.id, chapterName: chapter.name } as any;
                new SceneModal(context.app, context.plugin, newScene, async (scene) => {
                    scene.chapterId = chapter.id;
                    scene.chapterName = chapter.name;
                    await context.persistScene(scene, `Scene "${scene.name}" created in chapter "${chapter.name}".`, 'writing-scene-created-in-chapter');
                }).open();
            });
        };

        const chapterKey = chapter.id || chapter.name;
        let isExpanded = context.chapterCollapseState.has(chapterKey) ? context.chapterCollapseState.get(chapterKey)! : true;
        if (!isExpanded) {
            scenesContainer.setCssStyles({ display: 'none' });
            toggleButton.classList.add('collapsed');
        }
        toggleButton.onclick = event => {
            event.stopPropagation();
            isExpanded = !isExpanded;
            context.chapterCollapseState.set(chapterKey, isExpanded);
            scenesContainer.setCssStyles({ display: isExpanded ? 'block' : 'none' });
            toggleButton.classList.toggle('collapsed', !isExpanded);
        };
    });

    const unassignedScenes = allScenes
        .filter(scene => !scene.chapterId && !scene.chapterName)
        .filter(scene =>
            scene.name.toLowerCase().includes(context.currentFilter) ||
            (scene.content || '').toLowerCase().includes(context.currentFilter)
        );

    if (unassignedScenes.length > 0) {
        const unassignedGroup = listContainer.createDiv('storyteller-chapter-group storyteller-unassigned-group');
        const unassignedHeader = unassignedGroup.createDiv('storyteller-chapter-header');

        const toggleButton = unassignedHeader.createDiv('storyteller-chapter-toggle');
        setIcon(toggleButton, 'chevron-down');

        const pfpContainer = unassignedHeader.createDiv('storyteller-list-item-pfp');
        pfpContainer.createDiv({ cls: 'storyteller-pfp-placeholder storyteller-unassigned-badge', text: '?' });

        const infoEl = unassignedHeader.createDiv('storyteller-list-item-info');
        const titleRow = infoEl.createDiv('storyteller-chapter-title-row');
        titleRow.createEl('strong', { text: 'Unassigned scenes' });
        titleRow.createSpan({ cls: 'storyteller-chapter-scene-count', text: `${unassignedScenes.length} scene${unassignedScenes.length !== 1 ? 's' : ''}` });

        const scenesContainer = unassignedGroup.createDiv('storyteller-chapter-scenes');
        unassignedScenes.forEach(scene => {
            renderWritingSceneItem(scenesContainer, scene, true, context, chapters);
        });

        const unassignedKey = '__unassigned__';
        let isExpanded = context.chapterCollapseState.has(unassignedKey) ? context.chapterCollapseState.get(unassignedKey)! : true;
        if (!isExpanded) {
            scenesContainer.setCssStyles({ display: 'none' });
            toggleButton.classList.add('collapsed');
        }
        toggleButton.onclick = event => {
            event.stopPropagation();
            isExpanded = !isExpanded;
            context.chapterCollapseState.set(unassignedKey, isExpanded);
            scenesContainer.setCssStyles({ display: isExpanded ? 'block' : 'none' });
            toggleButton.classList.toggle('collapsed', !isExpanded);
        };
    }
}

function renderWritingSceneItem(
    container: HTMLElement,
    scene: any,
    showChapterAssign: boolean,
    context: WritingListRendererContext,
    chapters?: any[],
): void {
    const itemEl = container.createDiv('storyteller-list-item storyteller-scene-item');

    const pfpContainer = itemEl.createDiv('storyteller-list-item-pfp');
    if (scene.profileImagePath) {
        const image = pfpContainer.createEl('img');
        try {
            image.src = context.getImageSrc(scene.profileImagePath);
            image.alt = scene.name;
        } catch {
            pfpContainer.createSpan({ text: '?' });
        }
    } else {
        pfpContainer.createDiv({ cls: 'storyteller-pfp-placeholder', text: scene.name.substring(0, 1) });
    }

    const infoEl = itemEl.createDiv('storyteller-list-item-info');
    const nameEl = infoEl.createEl('strong', { text: scene.name });
    if (scene.filePath) {
        nameEl.addClass('storyteller-scene-name-link');
        nameEl.title = 'Click to open note';
        nameEl.addEventListener('click', () => {
            const file = context.app.vault.getAbstractFileByPath(scene.filePath);
            if (file instanceof TFile) {
                void context.app.workspace.openLinkText(scene.filePath, '', false);
            }
        });
    }

    const meta = infoEl.createDiv('storyteller-list-item-extra');
    if (scene.status) {
        meta.createSpan({ cls: `storyteller-status-badge storyteller-status-${(scene.status || 'draft').toLowerCase().replace(/\s+/g, '-')}`, text: scene.status });
    }
    if (scene.povCharacter) {
        const pov = meta.createSpan({ cls: 'storyteller-scene-pov-badge' });
        setIcon(pov.createSpan(''), 'eye');
        pov.createSpan({ text: ` ${scene.povCharacter}` });
    }
    if (scene.emotion) {
        meta.createSpan({ text: scene.emotion, cls: `storyteller-scene-emotion-chip storyteller-emotion-${scene.emotion}` });
    }
    if (scene.tags && scene.tags.length > 0) {
        meta.createSpan({ text: scene.tags.map((tag: string) => `#${tag}`).join(' ') });
    }

    if (scene.intensity !== undefined && scene.intensity !== null) {
        const barWrap = infoEl.createDiv('storyteller-intensity-bar');
        const pct = Math.round(((Number(scene.intensity) + 10) / 20) * 100);
        const fill = barWrap.createDiv('storyteller-intensity-fill');
        fill.setCssStyles({ width: `${pct}%` });
        fill.title = `Intensity: ${scene.intensity}`;
    }

    if (scene.content) {
        const preview = scene.content.length > 80 ? `${scene.content.substring(0, 80)}...` : scene.content;
        infoEl.createEl('p', { cls: 'storyteller-scene-preview', text: preview });
    }

    const actionsEl = itemEl.createDiv('storyteller-list-item-actions');
    if (showChapterAssign && chapters && !scene.chapterId && !scene.chapterName) {
        const assignButton = actionsEl.createEl('button', { cls: 'storyteller-assign-chapter-btn', text: 'Assign' });
        assignButton.onclick = async () => {
            const select = container.createEl('select', { cls: 'storyteller-chapter-assign-select' });
            select.createEl('option', { value: '', text: 'Select chapter...' });
            chapters.forEach(chapter => {
                select.createEl('option', { value: chapter.id || chapter.name, text: `${chapter.number ?? '?'}. ${chapter.name}` });
            });
            select.onchange = async () => {
                const selectedChapter = chapters.find(chapter => (chapter.id || chapter.name) === select.value);
                if (selectedChapter) {
                    scene.chapterId = selectedChapter.id;
                    scene.chapterName = selectedChapter.name;
                    await context.persistScene(scene, `Scene assigned to chapter "${selectedChapter.name}"`, 'scene-assigned-to-chapter');
                }
            };
            assignButton.replaceWith(select);
            select.focus();
        };
    }

    context.addEditButton(actionsEl, () => {
        void import('../../../modals/SceneModal').then(({ SceneModal }) => {
            new SceneModal(context.app, context.plugin, scene, async (updated) => {
                await context.persistScene(updated, `Scene "${updated.name}" updated.`, 'scene-item-updated');
            }, async (toDelete) => {
                if (toDelete.filePath) {
                    await context.removeScene(toDelete.filePath, 'scene-item-deleted-from-modal');
                }
            }).open();
        });
    });
    context.addDeleteButton(actionsEl, async () => {
        if (scene.filePath) {
            await context.confirmDeleteScene(scene.filePath, scene.name, 'scene-item-deleted');
        }
    });
    context.addOpenFileButton(actionsEl, scene.filePath);
}
